import React, { useState } from 'react';
import Login from './components/Login';
import Signup from './components/Signup';
import Subscription from './components/Subscription';
import Swipe from './components/Swipe';
import Profile from './components/Profile';
import Chat from './components/Chat';
import Filter from './components/Filter';
import Notifications from './components/Notifications';

function App() {
  const [showLogin, setShowLogin] = useState(true);
  const [showSignup, setShowSignup] = useState(false);
  const [showSubscription, setShowSubscription] = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [showChat, setShowChat] = useState(false);
  const [showFilter, setShowFilter] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  const handleLogin = (userData) => {
    setCurrentUser(userData);
    setIsSubscribed(false);
    setShowLogin(false);
    setShowSignup(false);
    setShowProfile(false);
    setShowChat(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowLogin(true);
  };

  const handleSubscribe = (plan) => {
    alert(`✅ Abonnement ${plan.name} activé`);
    setIsSubscribed(true);
    setShowSubscription(false);
  };

  return (
    <div>
      {showLogin && <Login switchToSignup={() => { setShowLogin(false); setShowSignup(true); }} onLogin={handleLogin} />}
      {showSignup && <Signup switchToLogin={() => { setShowSignup(false); setShowLogin(true); }} />}
      {!showLogin && !showSignup && currentUser && (
        <>
          {showProfile ? <Profile user={currentUser} onUpdate={setCurrentUser} onBack={() => setShowProfile(false)} /> :
           showChat ? <Chat user={currentUser} onBack={() => setShowChat(false)} /> :
           showFilter ? <Filter onClose={() => setShowFilter(false)} /> :
           showNotifications ? <Notifications onClose={() => setShowNotifications(false)} /> :
           showSubscription ? <Subscription onSubscribe={handleSubscribe} onClose={() => setShowSubscription(false)} /> :
           <Swipe user={currentUser} onLogout={handleLogout} isSubscribed={isSubscribed} onSubscribe={() => setShowSubscription(true)} onProfile={() => setShowProfile(true)} onChat={() => setShowChat(true)} onFilter={() => setShowFilter(true)} onNotifications={() => setShowNotifications(true)} />}
        </>
      )}
    </div>
  );
}

export default App;
